def decode_ws_message(message):
    length = message[1] & 127
    if length == 126:
        length = (message[2] << 8) | message[3]
        mask_start = 4
    elif length == 127:
        length = (message[2] << 56) | (message[3] << 48) | (message[4] << 40) | (message[5] << 32) \
                  | (message[6] << 24) | (message[7] << 16) | (message[8] << 8) | message[9]
        mask_start = 10
    else:
        mask_start = 2

    masks = message[mask_start:mask_start + 4]
    decoded = bytearray(length)
    for i in range(length):
        decoded[i] = message[mask_start + 4 + i] ^ masks[i % 4]
    
    return decoded.decode('utf-8')

